using System.Collections.Generic; public sealed class BaseProgressState { private readonly Dictionary<string,int> _levels=new(); public int BaseLevel{get;private set;}=1; public int GetUpgradeLevel(string id)=>!string.IsNullOrWhiteSpace(id)&&_levels.TryGetValue(id,out int l)?l:0; public void IncreaseUpgradeLevel(string id){ if(string.IsNullOrWhiteSpace(id))return; _levels[id]=GetUpgradeLevel(id)+1; BaseLevel=System.Math.Max(BaseLevel,1+_levels.Count);} }